using UnityEngine;

public class PlaytestManager : MonoBehaviour
{
    [Header("Test Data")]
    public int playtestSessions = 0;
    public int totalBugsFound = 0;
    public int majorBugs = 0;
    public int minorBugs = 0;

    [Header("Feedback")]
    public string[] playerFeedback;
    public float averageRating = 0f;

    void Start()
    {
        Debug.Log("=== Playtesting and Iteration ===");
        Debug.Log("1. Get people to play your game");
        Debug.Log("2. Watch them play (don't explain!)");
        Debug.Log("3. Ask questions after");
        Debug.Log("4. Prioritize feedback");
        Debug.Log("5. Iterate and test again");

        // Test feedback
        if (Input.GetKeyDown(KeyCode.F))
        {
            RecordPlaytest();
        }
    }

    public void RecordPlaytest()
    {
        playtestSessions++;
        totalBugsFound += Random.Range(2, 10);
        majorBugs += Random.Range(0, 3);
        minorBugs += Random.Range(1, 5);

        Debug.Log("=== Playtest #" + playtestSessions + " ===");
        Debug.Log("Bugs Found: " + totalBugsFound + " (Major: " + majorBugs + ", Minor: " + minorBugs + ")");

        if (majorBugs > 0)
            Debug.Log("🔴 Major bugs found! Fix these first.");
        else
            Debug.Log("🟢 No major bugs found.");

        Debug.Log("\n--- Priority Order ---");
        Debug.Log("1. Fix major bugs");
        Debug.Log("2. Fix minor bugs");
        Debug.Log("3. Add polish");
        Debug.Log("4. Test again");
    }

    public void AddFeedback(string feedback, int rating)
    {
        Debug.Log("Feedback: " + feedback);
        Debug.Log("Rating: " + rating + "/5");
    }
}

